// 可視領域の高さ（iOS Safari のツールバーを除いた実寸）を CSS 変数に反映
function setVVH() {
  const h = (window.visualViewport && window.visualViewport.height) || window.innerHeight;
  document.documentElement.style.setProperty("--vvh", Math.round(h) + "px");
}
setVVH();
if (window.visualViewport) {
  window.visualViewport.addEventListener("resize", setVVH);
  window.visualViewport.addEventListener("scroll", setVVH);
}
window.addEventListener("orientationchange", () => setTimeout(setVVH, 300));
window.addEventListener("load", setVVH);

// OS の「視差効果を減らす」設定（true ならアニメーションを抑える）
const reduceMotion = window.matchMedia("(prefers-reduced-motion: reduce)").matches;
// ビューを差し替えた時にふわっとフェードインさせる
function playFadeIn(el) {
  if (reduceMotion || !el) return;
  el.classList.remove("view-in");
  void el.offsetWidth;            // reflow してアニメを再生し直す
  el.classList.add("view-in");
}

// HTML特殊文字をエスケープ（フォルダ名/画像名に < & " 等が入っても崩れない）
function esc(s) {
  return String(s ?? "").replace(/[&<>"']/g, c =>
    ({ "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;", "'": "&#39;" }[c]));
}

// ═══════════════════════════════════════════════════════════
//  GALLERY DATA  ← Cloudinary（/api/gallery）から取得
//  失敗時（ローカルプレビュー等）は data.folders にフォールバック
// ═══════════════════════════════════════════════════════════
let sections = [];
async function loadGallery() {
  try {
    const r = await fetch("/api/gallery", { cache: "no-cache" });
    if (r.ok) {
      const j = await r.json();
      if (Array.isArray(j.sections)) return j.sections;
    }
  } catch {}
  return fallbackSections();
}
function fallbackSections() {
  const mk = (label, allLabel, allId, section) => ({
    id: section, label, allLabel, allId,
    folders: data.folders
      .filter(f => f.section === section)
      .map(f => ({ id: f.id, name: f.name, marker: f.marker, images: f.images || [] })),
  });
  return [
    mk("Selected Work", "(all) Work", "all", "selected-work"),
    mk("Experiments", "(all) Experiments", "all-exp", "experiments"),
  ];
}
function findFolder(id) {
  for (const s of sections) { const f = s.folders.find(x => x.id === id); if (f) return f; }
  return null;
}
const sectionByAllId = (allId) => sections.find(s => s.allId === allId);

// フォルダの中身（画像）は「開いた時」に取得する（初回ロードを軽くするため）
const loadedFolders = new Set();
async function ensureFolderImages(folder) {
  if (!folder) return [];
  // 既に取得済み / フォールバックで画像を持っている場合はそのまま
  if (loadedFolders.has(folder.id) || (folder.images && folder.images.length)) {
    loadedFolders.add(folder.id);
    return folder.images || [];
  }
  try {
    const r = await fetch(`/api/gallery?folder=${encodeURIComponent(folder.id)}`, { cache: "no-cache" });
    const j = await r.json();
    folder.images = Array.isArray(j.images) ? j.images : [];
  } catch {
    folder.images = folder.images || [];
  }
  loadedFolders.add(folder.id);
  return folder.images;
}

// ═══════════════════════════════════════════════════════════
//  SIDEBAR
// ═══════════════════════════════════════════════════════════
function renderNav() {
  const parts = [];

  // Overview (no section label)
  parts.push(`
    <div class="nav-section">
      <ul class="nav-list">
        <li class="nav-item" data-view="overview">
          ${navFolderGlyph()}<span class="label">Overview</span>
        </li>
      </ul>
    </div>`);

  // Sections (from Cloudinary). 空のセクションは出さない。
  for (const s of sections) {
    if (!s.folders.length) continue;
    parts.push(`
      <div class="nav-section">
        <p class="nav-label">${esc(s.label)}</p>
        <ul class="nav-list">
          <li class="nav-item" data-view="${s.allId}">
            ${navFolderGlyph()}<span class="label">${esc(s.allLabel)}</span>
          </li>
          ${s.folders.map(navItem).join("")}
        </ul>
      </div>`);
  }

  // Links
  if (data.links.length) {
    parts.push(`
      <div class="nav-section">
        <p class="nav-label">Links</p>
        <ul class="nav-list">
          ${data.links.map(l => `
            <li class="nav-item link-item">
              ${l.icon || dotSpan(l.color)}
              <a href="${l.url}" target="_blank" rel="noopener" class="label">${l.name}</a>
              <span class="ext-arrow">&#8599;</span>
            </li>`).join("")}
        </ul>
      </div>`);
  }

  nav.innerHTML = `<div class="nav-inner">${parts.join("")}</div>`;

  nav.querySelectorAll("[data-view]").forEach(el =>
    el.addEventListener("click", () => go(el.dataset.view))
  );
}

function navItem(f) {
  return `<li class="nav-item" data-view="folder:${esc(f.id)}">
    ${navFolderGlyph()}<span class="label">${esc(f.name)}</span>${dotSpan(f.marker)}
  </li>`;
}

// ═══════════════════════════════════════════════════════════
//  OVERVIEW  (files + folders)
// ═══════════════════════════════════════════════════════════
function renderOverview() {
  const fileCell = file => `
    <div class="cell file-cell" data-file="${esc(file.name)}" title="${esc(file.name)}">
      <div class="cell-icon">${fileIcon(file)}</div>
      <span class="cell-caption">${esc(file.name)}${file.url ? ' <span class="ext-arrow">&#8599;</span>' : ""}</span>
    </div>`;

  const folderCell = f => `
    <div class="cell folder-cell" data-view="folder:${esc(f.id)}" title="${esc(f.name)}">
      <div class="cell-icon">${folderIcon()}</div>
      <span class="cell-caption">${dotSpan(f.marker)}${esc(f.name)}</span>
    </div>`;

  // One row-group per sidebar section, separated by a divider
  const groups = [];
  if (data.files.length) groups.push(data.files.map(fileCell).join(""));
  for (const s of sections) {
    if (s.folders.length) groups.push(s.folders.map(folderCell).join(""));
  }

  overviewView.innerHTML = groups
    .map(g => `<div class="ov-group">${g}</div>`)
    .join('<hr class="ov-divider">');

  overviewView.querySelectorAll("[data-view]").forEach(el =>
    el.addEventListener("click", () => go(el.dataset.view))
  );
  overviewView.querySelectorAll("[data-file]").forEach(el =>
    el.addEventListener("click", () => {
      const f = data.files.find(x => x.name === el.dataset.file);
      if (!f) return;
      if (f.body) openDoc(f);
      else if (f.url && f.url !== "#") window.open(f.url, "_blank");
    })
  );
}

// ── Document popup ──
const docModal = document.getElementById("doc-modal");
const docTitle = document.getElementById("doc-title");
const docBody  = document.getElementById("doc-body");
function openDoc(file) {
  docTitle.textContent = file.name;
  docBody.innerHTML = file.body;
  // 末尾に点滅カーソル（飾り）
  (docBody.lastElementChild || docBody)
    .insertAdjacentHTML("beforeend", '<span class="caret" aria-hidden="true"></span>');
  docModal.classList.remove("hidden");
}
function closeDoc() { docModal.classList.add("hidden"); }
document.getElementById("doc-close").addEventListener("click", closeDoc);
docModal.addEventListener("click", e => { if (e.target === docModal) closeDoc(); });
document.addEventListener("keydown", e => {
  if (e.key === "Escape" && !docModal.classList.contains("hidden")) closeDoc();
});

// ═══════════════════════════════════════════════════════════
//  IMAGE GRID
// ═══════════════════════════════════════════════════════════
let lbImages = [];   // 現在表示中の画像リスト
let lbIndex  = 0;

// Cloudinary URL に幅リサイズを差し込む（c_limit = 元より大きくはしない）
const sized = (url, w) => url.replace("/f_auto,q_auto/", `/f_auto,q_auto,c_limit,w_${w}/`);

// 読み込み前にスペース確保するためのアスペクト比（w/h、なければURL末尾の寸法から推定）
function imgAspect(img) {
  if (img.w && img.h) return `${img.w}/${img.h}`;
  const m = String(img.url).match(/\/(\d+)\/(\d+)(?:[?#]|$)/);
  return m ? `${m[1]}/${m[2]}` : "";
}
// 低画質ブラー（blur-up）用の極小URL。Cloudinary 配信URLのみ。
function blurURL(url) {
  return url.includes("/f_auto,q_auto/")
    ? url.replace("/f_auto,q_auto/", "/w_24,e_blur:1200,q_30,f_auto/")
    : "";
}

// サムネ解像度は「1カラム表示」を前提に固定（＝表示領域いっぱいの幅 × DPR、上限2400）。
// カラム数に依存しないので、スライダーで変えても再読み込みは起きない。
function thumbW() {
  const avail = imageView.clientWidth || window.innerWidth;
  const dpr = Math.min(window.devicePixelRatio || 1, 2);
  return Math.min(2400, Math.ceil((avail * dpr) / 100) * 100);
}

function renderImages(images) {
  lbImages = images;
  document.body.classList.remove("booting");  // 読込中の高さ予約を解除（iOS 帯対策）
  imageView.style.minHeight = "";   // 前ビューの高さ予約が残らないようにクリア
  if (!images.length) {            // 空フォルダ
    imageView.innerHTML = `<p class="empty-note">No images</p>`;
    return;
  }
  const tw = thumbW();
  imageView.innerHTML = images.map(img => {
    const ar = imgAspect(img);
    const blur = blurURL(img.url);
    const style =
      (ar ? `aspect-ratio:${ar};` : "") +
      (blur ? `background-image:url('${blur}');` : "");
    const name = esc(img.name || "");
    return `
    <div class="cell photo-cell" title="${name}">
      <div class="cell-icon"${style ? ` style="${style}"` : ""}>
        <img src="${sized(img.url, tw)}" loading="lazy" alt="${name}">
      </div>
      <span class="cell-caption">${dotSpan(img.marker)}${name}</span>
    </div>`;
  }).join("");

  imageView.querySelectorAll(".photo-cell img").forEach((im, i) => {
    im.addEventListener("click", () => openLightbox(i));
    // 読み込み完了でフェードイン（キャッシュ済みは即時）
    if (im.complete && im.naturalWidth) im.classList.add("is-loaded");
    else im.addEventListener("load", () => im.classList.add("is-loaded"), { once: true });
  });
}

// ═══════════════════════════════════════════════════════════
//  ROUTING
// ═══════════════════════════════════════════════════════════
function setActive(view) {
  nav.querySelectorAll(".nav-item").forEach(el =>
    el.classList.toggle("active", el.dataset.view === view)
  );
}

function showOverview() {
  overviewView.classList.remove("hidden");
  imageView.classList.add("hidden");
  gridSlider.classList.add("hidden");        // slider only for thumbnails
  document.body.classList.remove("view-images", "booting");
}
function showImages() {
  overviewView.classList.add("hidden");
  imageView.classList.remove("hidden");
  gridSlider.classList.remove("hidden");
  document.body.classList.add("view-images"); // スマホは写真一覧でページ全体スクロールに
}

let routeSeq = 0;
async function route(view) {
  const seq = ++routeSeq;
  setActive(view);

  if (view === "overview") { showOverview(); playFadeIn(overviewView); pagesScroll?.scrollTo({ top: 0 }); window.scrollTo(0, 0); return; }

  showImages();
  pagesScroll?.scrollTo({ top: 0 });
  window.scrollTo(0, 0);   // ページ全体スクロール時も先頭へ戻す

  // 対象フォルダを決める（All ○○ はセクション内の全フォルダを集約）
  let folders = [];
  const sec = sectionByAllId(view);
  if (sec) folders = sec.folders;
  else if (view.startsWith("folder:")) {
    const f = findFolder(view.slice(7));
    folders = f ? [f] : [];
  }

  // 未取得のフォルダがあれば、取得中は前のフォルダの画像を残さない
  const needFetch = folders.some(f => !loadedFolders.has(f.id) && !(f.images && f.images.length));
  if (needFetch) imageView.innerHTML = "";

  const arrays = await Promise.all(folders.map(ensureFolderImages));
  if (seq !== routeSeq) return;   // 競合: 取得中に別の遷移が始まっていたら破棄
  renderImages(arrays.flat());
  playFadeIn(imageView);
  // Overview から遷移してきた場合、帯が確定したままなので再評価を促す
  requestAnimationFrame(() => requestAnimationFrame(refreshBarTransparency));
}

// ═══════════════════════════════════════════════════════════
//  LIGHTBOX
// ═══════════════════════════════════════════════════════════
// 画像とキャプション・矢印だけを差し替える（開閉アニメとは独立）
function setLbImage(i) {
  lbIndex = (i + lbImages.length) % lbImages.length;
  const img = lbImages[lbIndex];
  lbImg.src = img.url;
  lbImg.alt = img.name || "";
  lbCaption.textContent = img.name || "";
  const single = lbImages.length <= 1;   // 1枚しかなければ矢印を隠す
  lbPrev.classList.toggle("hidden", single);
  lbNext.classList.toggle("hidden", single);
  preloadAdjacent();                     // 次/前を先読みして送りを速く
}
// 次・前の画像をブラウザキャッシュに先読み
function preloadAdjacent() {
  if (lbImages.length <= 1) return;
  for (const d of [1, -1]) {
    const n = lbImages[(lbIndex + d + lbImages.length) % lbImages.length];
    if (n && n.url) { const im = new Image(); im.src = n.url; }
  }
}
let lbReturnFocus = null;                 // 閉じた後にフォーカスを戻す先
// ライトボックス表示中、背景ページがスクロールしないように固定（スマホの写真一覧＝ページ全体スクロール時のみ）
let lockedScrollY = 0, scrollLocked = false;
function lockScroll() {
  if (scrollLocked) return;
  if (!(window.innerWidth <= MOBILE_BP && document.body.classList.contains("view-images"))) return;
  lockedScrollY = window.scrollY;
  document.body.style.position = "fixed";
  document.body.style.top = `-${lockedScrollY}px`;
  document.body.style.left = "0";
  document.body.style.right = "0";
  scrollLocked = true;
}
function unlockScroll() {
  if (!scrollLocked) return;
  document.body.style.position = "";
  document.body.style.top = "";
  document.body.style.left = "";
  document.body.style.right = "";
  window.scrollTo(0, lockedScrollY);
  scrollLocked = false;
}
// iOS 26 の帯対策（ページ内遷移用）：Overview（固定シェル＝スクロール不可）の間に
// Safari がタブバー裏の不透過の帯を確定させると、写真一覧へ遷移しても再評価されない。
// 実測で「プレビュー開閉をすると帯が消える」ことが分かっているため、その状態
// （全画面の固定オーバーレイ + body スクロールロック）を不可視で短時間再現する。
function refreshBarTransparency() {
  if (window.innerWidth > MOBILE_BP) return;
  if (!document.body.classList.contains("view-images")) return;
  if (scrollLocked) return;                  // 実際のプレビュー表示中は不要
  const ov = document.createElement("div");
  ov.style.cssText =
    "position:fixed;inset:0;pointer-events:none;z-index:2000;" +
    "background:rgba(0,0,0,0.001);" +
    "-webkit-backdrop-filter:blur(0.5px);backdrop-filter:blur(0.5px);";
  document.body.appendChild(ov);
  lockScroll();
  setTimeout(() => {
    // この間にユーザーが実際にプレビューを開いていたら、解除は closeLightbox に任せる
    if (!lightbox.classList.contains("open")) unlockScroll();
    ov.remove();
  }, 450);
}

function openLightbox(i) {
  if (!lbImages.length) return;
  lbReturnFocus = document.activeElement; // 開く前のフォーカス位置を記憶
  lockScroll();                           // 背景スクロールをロック
  // 前の画像を「フェードさせず即座に」隠す（A→閉じる→B でAがチラ見えするのを防ぐ）
  lbImg.style.transition = "none";
  lbImg.classList.remove("shown");
  lbImg.style.transform = lbImg.style.opacity = "";   // インライン解除 → base（scale .93 / opacity 0）
  void lbImg.offsetWidth;                              // 反映
  setLbImage(i);                                       // 新しい src（読み込み開始）
  lbImg.style.transition = "";                         // CSS の transition に戻す
  lightbox.classList.remove("hidden");
  requestAnimationFrame(() => lightbox.classList.add("open"));
  // 自動フォーカスはしない（開いた瞬間に枠が出るのを防ぐ）。
  // キーボードで Tab した時だけ下の keydown ハンドラが枠付きでフォーカスを入れる。
  // 新しい画像が表示可能になってから画像をフェードイン
  const show = () => requestAnimationFrame(() => lbImg.classList.add("shown"));
  if (lbImg.complete && lbImg.naturalWidth) show();
  else {
    lbImg.addEventListener("load", show, { once: true });
    lbImg.addEventListener("error", show, { once: true });
  }
}
function closeLightbox() {
  lightbox.classList.remove("open");
  unlockScroll();                                                  // 背景スクロールのロック解除
  if (lbReturnFocus && lbReturnFocus.focus) lbReturnFocus.focus();  // 元の位置へフォーカスを戻す
}
// 前後送り：方向に合わせて左右へスライド＋フェード
function lbStep(d) {
  if (lbImages.length <= 1) return;
  if (reduceMotion) { setLbImage(lbIndex + d); return; }
  const dir = d > 0 ? 1 : -1;
  const OUT = 210, DIST = 60;
  lbImg.style.transition = `transform ${OUT}ms cubic-bezier(0.4,0,1,1), opacity ${OUT}ms ease-in`;
  lbImg.style.transform = `translateX(${-dir * DIST}px)`;
  lbImg.style.opacity = "0";
  setTimeout(() => {
    setLbImage(lbIndex + d);                                  // 新しい src（読み込み開始）
    const slideIn = () => {
      lbImg.style.transition = "none";
      lbImg.style.transform = `translateX(${dir * DIST}px)`;  // 反対側から入ってくる
      void lbImg.offsetWidth;                                 // reflow を強制
      lbImg.style.transition = "transform 0.42s var(--ease-out), opacity 0.36s ease-out";
      lbImg.style.transform = "translateX(0)";
      lbImg.style.opacity = "1";
    };
    // 新しい画像が用意できてからスライドイン（前の画像のチラ見え防止）
    if (lbImg.complete && lbImg.naturalWidth) slideIn();
    else {
      lbImg.addEventListener("load", slideIn, { once: true });
      lbImg.addEventListener("error", slideIn, { once: true });
    }
  }, OUT);
}

lbClose.addEventListener("click", e => { e.stopPropagation(); closeLightbox(); });
lbPrev.addEventListener("click", e => { e.stopPropagation(); lbStep(-1); });
lbNext.addEventListener("click", e => { e.stopPropagation(); lbStep(1); });
lightbox.addEventListener("click", e => { if (e.target === lightbox) closeLightbox(); });

document.addEventListener("keydown", e => {
  if (!lightbox.classList.contains("open")) return;
  if (e.key === "Escape") closeLightbox();
  else if (e.key === "ArrowLeft") lbStep(-1);
  else if (e.key === "ArrowRight") lbStep(1);
  else if (e.key === "Tab") {
    // フォーカスをライトボックス内のボタンに閉じ込める
    const f = [lbClose, lbPrev, lbNext].filter(b => b && !b.classList.contains("hidden"));
    if (!f.length) return;
    e.preventDefault();
    const i = f.indexOf(document.activeElement);
    const n = e.shiftKey ? (i <= 0 ? f.length - 1 : i - 1) : (i >= f.length - 1 ? 0 : i + 1);
    f[n].focus();
  }
});

// Swipe navigation (mobile) — left = next, right = prev
let touchX = null, touchY = null;
lightbox.addEventListener("touchstart", e => {
  const t = e.changedTouches[0];
  touchX = t.clientX; touchY = t.clientY;
}, { passive: true });
lightbox.addEventListener("touchend", e => {
  if (touchX === null) return;
  const t = e.changedTouches[0];
  const dx = t.clientX - touchX, dy = t.clientY - touchY;
  touchX = touchY = null;
  if (Math.abs(dx) > 45 && Math.abs(dx) > Math.abs(dy) * 1.5) lbStep(dx < 0 ? 1 : -1);
}, { passive: true });

// ═══════════════════════════════════════════════════════════
//  GRID SIZE SLIDER  (Finder-style: left = 多カラム / right = 少カラム)
//  PC: 6→1 (既定 6) / Mobile: 3→1 (既定 2)
// ═══════════════════════════════════════════════════════════
const MOBILE_BP = 760;
const lsGet = k => { try { return localStorage.getItem(k); } catch { return null; } };
const lsSet = (k, v) => { try { localStorage.setItem(k, v); } catch {} };

function maxCols()     { return window.innerWidth <= MOBILE_BP ? 3 : 6; }   // 段階の上限
function defaultCols() { return window.innerWidth <= MOBILE_BP ? 2 : 4; }   // 既定（保存値が無い時）

function currentCols() {
  const mc = maxCols();
  let c = parseInt(lsGet("img-cols"), 10);
  if (!Number.isInteger(c) || c < 1) c = defaultCols();   // 既定: スマホ2 / PC6
  return Math.min(Math.max(c, 1), mc);
}

// 列数は :root に設定 → Overview・画像グリッド両方に効く。
// サムネは FLIP で「実際に拡縮しながら」滑らかに動かす（瞬間的な組み替えにしない）。
let _appliedCols = null;
let _reserveTimer = null;   // Mobile: 列変更アニメ中だけグリッド高さを予約するタイマー
let _clipTimer = null;      // Mobile: アニメ後に clip-path を掃除するタイマー
function applyCols(c) {
  if (c === _appliedCols) return;        // 列数が変わらない時は何もしない（連続入力の無駄打ち防止）
  const prev = _appliedCols;
  _appliedCols = c;
  const setVar = () => document.documentElement.style.setProperty("--img-cols", c);
  if (reduceMotion || prev === null || imageView.classList.contains("hidden")) { setVar(); return; }

  const icons = [...imageView.querySelectorAll(".photo-cell .cell-icon")];
  if (!icons.length) { setVar(); return; }
  const movers = [...icons, ...imageView.querySelectorAll(".photo-cell .cell-caption")];
  const scaled = new Set(icons);
  const isMobile = window.innerWidth <= MOBILE_BP;
  const pageScroll = isMobile && document.body.classList.contains("view-images");

  // First: 現在の見た目（進行中アニメの途中位置も含む）
  const first = movers.map(el => el.getBoundingClientRect());

  // ページ全体スクロール時は、画面上端のサムネを基準にスクロール位置がズレないようにする
  let anchorEl = null, anchorTop = 0;
  if (pageScroll) {
    let best = Infinity;
    for (let i = 0; i < icons.length; i++) {
      const t = first[i].top;
      if (t >= -40 && t < best) { best = t; anchorEl = icons[i]; anchorTop = t; }
    }
    if (!anchorEl) { anchorEl = icons[0]; anchorTop = first[0].top; }
  }

  // Mobile（ページ全体スクロール）用に、変更前のグリッド高さを控えておく
  const gridH0 = pageScroll ? imageView.getBoundingClientRect().height : 0;

  movers.forEach(el => { el.style.transition = "none"; el.style.transform = ""; });
  setVar();
  // Mobile では列変更でグリッド高が急に縮むとページのスクロール位置がクランプされ、
  // サイト全体がガクッと跳ねて見える。アニメ中だけ高さを「変更前後の大きい方」で固定して
  // 急な伸縮を抑え、終わってから自然な高さに戻す（PC は内部スクロールなので無関係）。
  if (pageScroll) {
    const gridH1 = imageView.getBoundingClientRect().height;
    imageView.style.minHeight = Math.max(gridH0, gridH1) + "px";
    clearTimeout(_reserveTimer);
    _reserveTimer = setTimeout(() => { imageView.style.minHeight = ""; }, 460);
  }
  if (pageScroll && anchorEl) {
    const after = anchorEl.getBoundingClientRect().top;
    if (after !== anchorTop) window.scrollBy(0, after - anchorTop);
  }
  const last = movers.map(el => el.getBoundingClientRect());

  // 角丸の処理:
  //  PC   … border-radius を逆補正してアニメ（従来通り）。
  //  スマホ … border-radius は scale 中に再ラスタライズされて角がガクつくため、
  //          アニメ中だけ角丸を clip-path（GPU 側のマスク）に差し替える。
  //          マスクは transform と一緒に滑らかにスケールされるので、毎フレームの
  //          スタイル更新（メインスレッド負荷）なしで角の安定が得られる。
  //          ※ clip-path 自体はアニメさせない＝合成スレッドだけで完結。
  const R = parseFloat(getComputedStyle(document.documentElement).getPropertyValue("--thumb-radius")) || 0;
  const useClip = isMobile && R > 0 &&
    typeof CSS !== "undefined" && CSS.supports("clip-path", "inset(0 round 1px)");
  const usePC = !isMobile && R > 0;

  movers.forEach((el, i) => {
    const f = first[i], l = last[i];
    if (!l.width || !l.height) return;
    el.style.transformOrigin = "top left";
    const sx = f.width / l.width, sy = f.height / l.height;
    const move = `translate(${f.left - l.left}px, ${f.top - l.top}px)`;
    if (scaled.has(el)) {
      el.style.transform = `${move} scale(${sx}, ${sy})`;
      if (useClip) {
        el.style.borderRadius = "0px";   // 二重クリップ回避（img は inherit で 0 に）
        el.style.clipPath = `inset(0 round ${R}px)`;
      } else if (usePC) {
        el.style.borderRadius = (R / sx) + "px";
      }
    } else {
      el.style.transform = move;
    }
  });
  requestAnimationFrame(() => {
    const trans = usePC
      ? "transform 0.42s var(--ease), border-radius 0.42s var(--ease)"
      : "transform 0.42s var(--ease)";
    movers.forEach(el => {
      el.style.transition = trans;
      el.style.transform = "";
      if (usePC && scaled.has(el)) el.style.borderRadius = "";
    });
  });
  // アニメ終了後に clip-path を外し、通常の border-radius クリップへ戻す
  // （終了時は両者とも半径 R なので見た目は変わらない）
  if (useClip) {
    clearTimeout(_clipTimer);
    _clipTimer = setTimeout(() => {
      icons.forEach(el => {
        el.style.clipPath = ""; el.style.borderRadius = "";
      });
    }, 460);
  }
}

// スマホ用：1ボタンのカラム調整（端で向きが反転するバウンス式）
const gridToggle = document.getElementById("grid-toggle");
let toggleDir = -1;   // -1: 押すと列を減らす(＝大きく / 「+」表示) / +1: 増やす(＝小さく / 「−」表示)
function updateToggle(c) {
  const mc = maxCols();
  if (c <= 1) toggleDir = +1;          // 最小 → 次は小さく（−）
  else if (c >= mc) toggleDir = -1;    // 最大 → 次は大きく（+）
  // 中間は今の向きを維持
  if (gridToggle) {
    gridToggle.classList.toggle("plus", toggleDir === -1);
    gridToggle.setAttribute("aria-label", toggleDir === -1 ? "サムネイルを大きく" : "サムネイルを小さく");
  }
}
// カラム数を確定（描画＋保存＋ボタン同期）— ボタン/ピンチ共通
function commitCols(c) {
  applyCols(c);
  lsSet("img-cols", c);
  updateToggle(c);
}
gridToggle?.addEventListener("click", () => {
  const mc = maxCols();
  commitCols(Math.min(Math.max(currentCols() + toggleDir, 1), mc));
});

// ── ピンチでカラム調整（スマホ）: 広げる=大きく(列減) / つまむ=小さく(列増) ──
let pinching = false, pinchDist0 = 0, pinchBaseCols = 0;
const touchDist = t => Math.hypot(t[0].clientX - t[1].clientX, t[0].clientY - t[1].clientY);
imageView.addEventListener("touchstart", e => {
  if (e.touches.length === 2) {
    pinching = true;
    pinchDist0 = touchDist(e.touches);
    pinchBaseCols = currentCols();
  }
}, { passive: true });
imageView.addEventListener("touchmove", e => {
  if (!pinching || e.touches.length !== 2) return;
  e.preventDefault();                          // ブラウザのズームを止める
  const ratio = touchDist(e.touches) / pinchDist0;
  const STEP = 1.4;                            // この倍率を超えたら1段階
  if (ratio >= STEP) {                         // 広げる → 大きく（列を減らす）
    const c = Math.max(1, pinchBaseCols - 1);
    if (c !== pinchBaseCols) { commitCols(c); pinchBaseCols = c; pinchDist0 = touchDist(e.touches); }
  } else if (ratio <= 1 / STEP) {              // つまむ → 小さく（列を増やす）
    const c = Math.min(maxCols(), pinchBaseCols + 1);
    if (c !== pinchBaseCols) { commitCols(c); pinchBaseCols = c; pinchDist0 = touchDist(e.touches); }
  }
}, { passive: false });
imageView.addEventListener("touchend", e => { if (e.touches.length < 2) pinching = false; }, { passive: true });
imageView.addEventListener("touchcancel", () => { pinching = false; }, { passive: true });

function syncSlider() {
  const mc = maxCols();
  const c = currentCols();
  gsRange.min = 1;
  gsRange.max = mc;
  gsRange.step = "any";          // つまみを段階でなく連続的に動かす（カクつき防止）
  gsRange.value = mc + 1 - c;    // 左端 = 最大カラム
  applyCols(c);
  updateToggle(c);               // スマホの1ボタンの向き/表示も同期
}

gsRange.addEventListener("input", () => {
  const mc = maxCols();
  // 連続値 → 最寄りのカラム数に丸める（ドラッグ中はつまみが滑らかに動く）
  const c = Math.min(Math.max(mc + 1 - Math.round(parseFloat(gsRange.value)), 1), mc);
  applyCols(c);
  lsSet("img-cols", c);
  updateToggle(c);
});

// 指を離したら、対応するカラム位置（段）へつまみをスナップ → 中途半端な位置で止まらない
gsRange.addEventListener("change", () => {
  gsRange.value = maxCols() + 1 - currentCols();
});

let rT;
window.addEventListener("resize", () => { clearTimeout(rT); rT = setTimeout(syncSlider, 120); });

// ═══════════════════════════════════════════════════════════
//  MOBILE MENU (sidebar pulldown)
// ═══════════════════════════════════════════════════════════
function setMenu(open) {
  sidebar.classList.toggle("open", open);
  menuToggle.setAttribute("aria-expanded", String(open));
}
menuToggle.addEventListener("click", () => setMenu(!sidebar.classList.contains("open")));

// メニュー項目を選んだら閉じる（モバイルのみ）
nav.addEventListener("click", e => {
  if (window.innerWidth <= MOBILE_BP && e.target.closest(".nav-item")) setMenu(false);
});

// ── ハッシュルーティング（URL連動 + ブラウザの戻る/進む対応）──
function viewFromHash() {
  const h = decodeURIComponent(location.hash.replace(/^#/, ""));
  return h || "overview";
}
// 画面遷移は URL（ハッシュ）を更新 → hashchange が route() を呼ぶ
function go(view) {
  const want = "#" + encodeURIComponent(view);
  if (location.hash !== want) location.hash = want;  // 履歴に積まれる → 戻るで前の画面へ
  else route(view);                                  // 同じ画面の再選択
  if (window.innerWidth <= MOBILE_BP) setMenu(false);
}
window.addEventListener("hashchange", () => route(viewFromHash()));

// 信号機ボタン → 赤: トップ(Overview) / 緑: 全作品(All Work)
document.querySelector(".tl-red")?.addEventListener("click", () => go("overview"));
document.querySelector(".tl-green")?.addEventListener("click", () => go(sections[0]?.allId || "all"));

// ═══════════════════════════════════════════════════════════
//  FOOTER CLOCK  — realtime timestamp + timezone
//  © YYYYMMDD_HHMMSS.mmm_UTC±H  MYJPEG.JP
// ═══════════════════════════════════════════════════════════
const footerClock = document.getElementById("footer-clock");
const pad = (n, len = 2) => String(n).padStart(len, "0");

function tzLabel() {
  const off = -new Date().getTimezoneOffset();   // minutes east of UTC (JST = +540)
  const sign = off >= 0 ? "+" : "-";
  const abs = Math.abs(off);
  const h = Math.floor(abs / 60), m = abs % 60;
  return `UTC${sign}${h}${m ? ":" + pad(m) : ""}`;
}

function tickClock() {
  // PC・スマホ共通のフルタイムスタンプ
  const d = new Date();
  footerClock.textContent =
    `© ${d.getFullYear()}${pad(d.getMonth() + 1)}${pad(d.getDate())}_` +
    `${pad(d.getHours())}${pad(d.getMinutes())}${pad(d.getSeconds())}.${pad(d.getMilliseconds(), 3)}` +
    `_${tzLabel()} MYJPEG.JP`;
  requestAnimationFrame(tickClock);
}
tickClock();

// ═══════════════════════════════════════════════════════════
//  INIT
// ═══════════════════════════════════════════════════════════
(async () => {
  sections = await loadGallery();   // Cloudinary からフォルダ＆画像を取得
  renderNav();
  renderOverview();
  syncSlider();
  route(viewFromHash());            // ← URL のハッシュに応じた初期表示（直リンク対応）
})();
